/// // let vault = Vault::from_file("config.json")?;
/// ```
pub fn from_file(path: &str) -> Result<Self, String> {
    // ...
}
```

---

### 섹션 4️⃣: Safety (unsafe 함수일 때)

```rust
/// Unsafe function that bypasses authentication checks.
///
/// # Safety
///
/// This function is unsafe because it skips all security checks.
/// Caller must guarantee:
/// - The caller is authorized to perform this action
/// - No concurrent modifications are happening
///
/// # Examples
///
/// ```
/// // Unsafe usage - only in trusted contexts
/// unsafe {
///     // vault.skip_authentication();
/// }
/// ```
unsafe fn skip_authentication(&mut self) {
    // ...
}
```

